export interface ShipmentRequest {
  recipient_name?: string | null;
  weight_kg?: number | null;
  shipment_type?: string | null;
  saturday_delivery?: boolean | null;
}

export interface ValidationError {
  field: string;
  code: string;
}

export interface ValidationResult {
  valid: boolean;
  errors: ValidationError[];
}

export function validateShipmentRequest(input: ShipmentRequest): ValidationResult {
  const errors: ValidationError[] = [];

  // AC2: recipient_name is required and must not be empty
  if (input.recipient_name == null || input.recipient_name.trim() === "") {
    errors.push({ field: "recipient_name", code: "REQUIRED" });
  }

  // AC3 & AC4: weight_kg must be positive and <= 1000
  if (input.weight_kg != null) {
    if (input.weight_kg <= 0) {
      errors.push({ field: "weight_kg", code: "MUST_BE_POSITIVE" });
    } else if (input.weight_kg > 1000) {
      errors.push({ field: "weight_kg", code: "EXCEEDS_MAX" });
    }
  }

  // AC5: express shipments require saturday_delivery
  if (input.shipment_type === "express" && input.saturday_delivery == null) {
    errors.push({ field: "saturday_delivery", code: "REQUIRED_FOR_EXPRESS" });
  }

  // AC6: standard shipments cannot have saturday_delivery
  if (input.shipment_type === "standard" && input.saturday_delivery != null) {
    errors.push({ field: "saturday_delivery", code: "NOT_APPLICABLE_FOR_STANDARD" });
  }

  return {
    valid: errors.length === 0,
    errors,
  };
}

